def validate(args, output):
    words = args[0]
    if not isinstance(output, str):
        return False
    # check every word appears as substring
    for w in words:
        if w not in output:
            return False
    # check length equals optimal
    # compute optimal length via DP on overlap
    n = len(words)
    overlap = [[0]*n for _ in range(n)]
    for i in range(n):
        for j in range(n):
            if i == j:
                continue
            # overlap[i][j] = max len of suffix of words[i] that is prefix of words[j]
            a, b = words[i], words[j]
            for k in range(min(len(a), len(b)), 0, -1):
                if a.endswith(b[:k]):
                    overlap[i][j] = k
                    break
    INF = float('inf')
    # dp[mask][i] = min total length of superstring covering words in mask, ending with words[i]
    total_len = [len(w) for w in words]
    dp = [[INF]*n for _ in range(1 << n)]
    for i in range(n):
        dp[1 << i][i] = total_len[i]
    for mask in range(1, 1 << n):
        for last in range(n):
            if not (mask >> last & 1):
                continue
            if dp[mask][last] == INF:
                continue
            for nxt in range(n):
                if mask >> nxt & 1:
                    continue
                new_mask = mask | (1 << nxt)
                new_len = dp[mask][last] + total_len[nxt] - overlap[last][nxt]
                if new_len < dp[new_mask][nxt]:
                    dp[new_mask][nxt] = new_len
    full = (1 << n) - 1
    opt = min(dp[full])
    return len(output) == opt

