function validate(args, output) {
    const words = args[0];
    if (typeof output !== 'string') return false;
    for (const w of words) if (!output.includes(w)) return false;
    const n = words.length;
    const totalLen = words.map(w => w.length);
    const overlap = Array.from({length:n}, () => new Array(n).fill(0));
    for (let i = 0; i < n; i++) for (let j = 0; j < n; j++) {
        if (i === j) continue;
        const a = words[i], b = words[j];
        for (let k = Math.min(a.length, b.length); k > 0; k--) {
            if (a.endsWith(b.slice(0, k))) { overlap[i][j] = k; break; }
        }
    }
    const INF = Infinity;
    const dp = Array.from({length: 1 << n}, () => new Array(n).fill(INF));
    for (let i = 0; i < n; i++) dp[1 << i][i] = totalLen[i];
    for (let mask = 1; mask < (1 << n); mask++) {
        for (let last = 0; last < n; last++) {
            if (!(mask >> last & 1) || dp[mask][last] === INF) continue;
            for (let nxt = 0; nxt < n; nxt++) {
                if (mask >> nxt & 1) continue;
                const newMask = mask | (1 << nxt);
                const newLen = dp[mask][last] + totalLen[nxt] - overlap[last][nxt];
                if (newLen < dp[newMask][nxt]) dp[newMask][nxt] = newLen;
            }
        }
    }
    const full = (1 << n) - 1;
    const opt = Math.min(...dp[full]);
    return output.length === opt;
}

