var shortestSuperstring = function(words) {
    const n = words.length;
    const overlap = Array.from({length:n}, () => new Array(n).fill(0));
    for (let i = 0; i < n; i++) for (let j = 0; j < n; j++) {
        if (i === j) continue;
        const a = words[i], b = words[j];
        for (let k = Math.min(a.length, b.length); k > 0; k--) {
            if (a.endsWith(b.slice(0, k))) { overlap[i][j] = k; break; }
        }
    }
    const INF = Infinity;
    const size = 1 << n;
    const dp = Array.from({length:size}, () => new Array(n).fill(INF));
    const par = Array.from({length:size}, () => new Array(n).fill(-1));
    for (let i = 0; i < n; i++) dp[1<<i][i] = words[i].length;
    for (let mask = 1; mask < size; mask++) {
        for (let last = 0; last < n; last++) {
            if (!(mask>>last&1) || dp[mask][last]===INF) continue;
            for (let nxt = 0; nxt < n; nxt++) {
                if (mask>>nxt&1) continue;
                const nm = mask|(1<<nxt);
                const nl = dp[mask][last]+words[nxt].length-overlap[last][nxt];
                if (nl < dp[nm][nxt]) { dp[nm][nxt]=nl; par[nm][nxt]=last; }
            }
        }
    }
    const full = size-1;
    let last = 0;
    for (let i = 1; i < n; i++) if (dp[full][i] < dp[full][last]) last = i;
    const path = [];
    let mask = full;
    while (last !== -1) {
        path.push(last);
        const prev = par[mask][last];
        mask ^= (1<<last);
        last = prev;
    }
    path.reverse();
    let result = words[path[0]];
    for (let k = 1; k < path.length; k++) {
        result += words[path[k]].slice(overlap[path[k-1]][path[k]]);
    }
    return result;
};
